Criando um componente para exportar dados em CSV é uma tarefa comum em desenvolvimento web. Abaixo está um exemplo simples de como você pode fazer isso usando React. Este exemplo assume que você tem um array de objetos que deseja exportar.

```jsx
import React from 'react';
import Papa from 'papaparse';

const ExportCSV = ({ data }) => {
  const handleExport = () => {
    // Convert the data to a CSV string
    const csvString = Papa.unparse(data);

    // Create a Blob from the CSV string
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });

    // Create an URL for the Blob
    const url = window.URL.createObjectURL(blob);

    // Create an anchor element and set its href to the URL
    const link = document.createElement('a');
    link.href = url;
    link.download = 'data.csv'; // Set the filename

    // Append the link to the document body and click it
    document.body.appendChild(link);
    link.click();

    // Remove the link from the document body
    document.body.removeChild(link);

    // Revoke the object URL
    window.URL.revokeObjectURL(url);
  };

  return (
    <button onClick={handleExport}>
      Exportar para CSV
    </button>
  );
};

export default ExportCSV;
